import{b as t,j as a}from"./chunks/theme.C9g6HaIV.js";import{c as r,Q as i,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const n="/videos/video-release-creation.webm",b=JSON.parse('{"title":"Releases","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/releases.md","filePath":"guide/admin/releases.md","lastUpdated":1778912818000}'),l={name:"guide/admin/releases.md"};function d(h,e,p,g,c,u){return i(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="releases" tabindex="-1">Releases <a class="header-anchor" href="#releases" aria-label="Permalink to &quot;Releases&quot;">​</a></h1><p>The <strong>Releases</strong> section is where you author releases, send them through the pipeline, approve them, and watch them deploy. See <a href="./../concepts/releases">Releases &amp; Deployments</a> for the conceptual model.</p><p>This page covers the release list and the release detail page. For creating a new release, see the section below. For the global pipeline configuration, see <a href="./release-configuration">Release Configuration</a>.</p><h2 id="list-page" tabindex="-1">List page <a class="header-anchor" href="#list-page" aria-label="Permalink to &quot;List page&quot;">​</a></h2><h3 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h3><ul><li><strong>Search</strong> — matches release name, version, and release notes text.</li><li><strong>Status</strong> — dynamically built from the release statuses present (Draft, In Progress, Paused, Completed, Failed, …).</li><li><strong>Type</strong> — Feature / Hotfix / Config.</li><li><strong>Clear</strong> — appears when any filter is active.</li><li><strong>New Release</strong> button (top right).</li><li>Count chip — filtered vs. total (&quot;3 of 12&quot;).</li></ul><h3 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Release</strong></td><td>Name or version, link to detail.</td></tr><tr><td><strong>Type</strong></td><td>Feature / Hotfix / Config badge.</td></tr><tr><td><strong>Status</strong></td><td>Lifecycle status badge.</td></tr><tr><td><strong>By</strong></td><td>Avatar of the initiator.</td></tr><tr><td><strong>Created</strong></td><td>Relative timestamp.</td></tr><tr><td><strong>Deployed</strong></td><td>When the release entered <code>in_progress</code>.</td></tr><tr><td><strong>Completed</strong></td><td>When the release finished.</td></tr></tbody></table><p>The list is read-only — every interaction is a navigation to detail.</p><h2 id="creating-a-new-release" tabindex="-1">Creating a new release <a class="header-anchor" href="#creating-a-new-release" aria-label="Permalink to &quot;Creating a new release&quot;">​</a></h2><video controls preload="metadata"><source src="'+n+'" type="video/webm"></video><p>Click <strong>New Release</strong>. The page is a two-step wizard: Form → Preview.</p><h3 id="step-1-—-form" tabindex="-1">Step 1 — Form <a class="header-anchor" href="#step-1-—-form" aria-label="Permalink to &quot;Step 1 — Form&quot;">​</a></h3><h4 id="release-setup" tabindex="-1">Release Setup <a class="header-anchor" href="#release-setup" aria-label="Permalink to &quot;Release Setup&quot;">​</a></h4><p>Pick a <strong>Release Type</strong>:</p><table tabindex="0"><thead><tr><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Feature</strong></td><td>New functionality. Deploys across all pipeline stages.</td></tr><tr><td><strong>Hotfix</strong></td><td>Critical fix. Auto-deploys and pauses pending feature releases.</td></tr><tr><td><strong>Config</strong></td><td>Environment-variable changes only. No image update.</td></tr></tbody></table><h4 id="version-bump-feature-only" tabindex="-1">Version Bump (Feature only) <a class="header-anchor" href="#version-bump-feature-only" aria-label="Permalink to &quot;Version Bump (Feature only)&quot;">​</a></h4><p>Three buttons: <strong>Patch</strong>, <strong>Minor</strong>, <strong>Major</strong>. The current version and the computed next version are shown so you can see what you are picking.</p><p>Hotfix releases always patch-bump regardless of selection. Config releases use an auto-incrementing counter (Config #1, #2, …).</p><h4 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h4><p>A rich-text editor with character count.</p><ul><li><strong>Required</strong> for Feature and Hotfix.</li><li><strong>Optional</strong> for Config.</li><li>Supports images, lists, formatting.</li><li>Toggle <strong>Focus Mode</strong> to expand the editor to full height.</li></ul><h4 id="service-images" tabindex="-1">Service Images <a class="header-anchor" href="#service-images" aria-label="Permalink to &quot;Service Images&quot;">​</a></h4><p>The right-hand column lists every service known to the pipeline.</p><ul><li>Use the checkboxes to include or exclude a service in this release.</li><li>For each included service, enter a <strong>Docker image tag or URL</strong>.</li><li>Click <strong>Current in production</strong> to pre-fill the image with what is currently deployed.</li><li>For Config releases, image inputs are hidden and all services are auto-included.</li></ul><p>When the form is valid, click <strong>Preview</strong>.</p><h3 id="step-2-—-preview" tabindex="-1">Step 2 — Preview <a class="header-anchor" href="#step-2-—-preview" aria-label="Permalink to &quot;Step 2 — Preview&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">Screenshot</p><p><em>Wizard Step 2 — Preview:</em> the read-only summary with Release Summary, Services, Env Changes (with Create/Update/Delete badges), and the Deployment Pipeline visualisation.</p></div><p>The preview is the read-only summary of what you are about to ship.</p><ul><li><strong>Release Summary</strong> — auto-generated name (e.g. &quot;Release v25.1.0&quot; or &quot;Config #42&quot;), type, version, semver bump.</li><li><strong>Services</strong> — included services with their target images.</li><li><strong>Env Changes</strong> — Create / Update / Delete deltas since the last deployed release. <ul><li>If this is a Config release and no changes are detected, a warning appears: the backend will reject the release.</li></ul></li><li><strong>Deployment Pipeline</strong> — numbered stages, environments inside each stage, instance counts, parallelism indicators.</li><li><strong>Release Notes</strong> — rendered rich text.</li></ul><p>Click <strong>Back</strong> to edit, or <strong>Create Release</strong> to submit. On success you land on the release detail page.</p><h3 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h3><ul><li>Services: at least one must be included (Feature / Hotfix).</li><li>Images: every included service requires a target image.</li><li>Notes: required for Feature / Hotfix.</li></ul><p>Errors appear in red alert boxes and the submit button is disabled until they are fixed.</p><h2 id="release-detail-page" tabindex="-1">Release detail page <a class="header-anchor" href="#release-detail-page" aria-label="Permalink to &quot;Release detail page&quot;">​</a></h2><h3 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h3><ul><li>Back link to Releases.</li><li>Release name, type badge, status badge.</li><li>A button to view release notes (modal).</li><li>Action buttons appropriate to the status: <ul><li><strong>Draft</strong> → <strong>Deploy</strong> (primary).</li><li><strong>Paused</strong> → <strong>Resume</strong> (primary).</li><li><strong>In Progress</strong> → <strong>Cancel Release</strong> (danger).</li><li><strong>Completed / Failed / Rolled Back / Cancelled</strong> → <strong>Archive</strong> (secondary).</li><li><strong>Archived (within 30 days)</strong> → <strong>Unarchive</strong> (secondary).</li></ul></li></ul><p>If archived, a notice shows the archive date and the unarchive deadline. After the deadline, per-service config, environment-version pin, and logs are permanently purged.</p><h3 id="release-info" tabindex="-1">Release info <a class="header-anchor" href="#release-info" aria-label="Permalink to &quot;Release info&quot;">​</a></h3><p>Version (or name for Config), Initiated By avatar, Created and Deployed timestamps.</p><h3 id="pipeline-visualisation" tabindex="-1">Pipeline visualisation <a class="header-anchor" href="#pipeline-visualisation" aria-label="Permalink to &quot;Pipeline visualisation&quot;">​</a></h3><p><img src="'+t+'" alt="Release pipeline visualisation" class="light-only"><img src="'+a+'" alt="Release pipeline visualisation" class="dark-only"></p><p>A horizontal flow of stages, numbered. Each stage contains environment boxes. Box borders reflect state:</p><table tabindex="0"><thead><tr><th>Border colour</th><th>Meaning</th></tr></thead><tbody><tr><td>Green</td><td>Deployed</td></tr><tr><td>Yellow</td><td>Deploying or paused</td></tr><tr><td>Red</td><td>Failed</td></tr><tr><td>Blue</td><td>Awaiting approval</td></tr><tr><td>Purple</td><td>Awaiting trigger</td></tr><tr><td>Grey</td><td>Pending</td></tr></tbody></table><p>Inside each environment box you see the status badge, started time, completed time, and <strong>Approve</strong> / <strong>Trigger</strong> buttons when an action is required.</p><h3 id="instance-deployments" tabindex="-1">Instance deployments <a class="header-anchor" href="#instance-deployments" aria-label="Permalink to &quot;Instance deployments&quot;">​</a></h3><p>Below the pipeline, each environment expands to a list of instances.</p><p>Per-instance row:</p><ul><li>Instance name (link to instance detail).</li><li>Status: pending / deploying / deployed / failed / rolled_back / skipped.</li><li>Optional message (e.g. error reason).</li><li>Action buttons: <ul><li><strong>Failed</strong> → Retry, Skip.</li><li><strong>Deployed</strong> → Rollback.</li><li><strong>Rolled Back</strong> → Skip.</li><li><strong>Skipped</strong> → display only.</li></ul></li></ul><p>Expand a row to see per-service deployment info — target image, previous image (struck through if changed), plus a snapshot sub-table for environment variables, with changed rows highlighted.</p><p>A toggle lets you show or hide unchanged instances.</p><h3 id="release-artifacts" tabindex="-1">Release artifacts <a class="header-anchor" href="#release-artifacts" aria-label="Permalink to &quot;Release artifacts&quot;">​</a></h3><p>The full bundle as a table: services with target images, environment variables in the snapshot (key + value or secret ref), and the delta from the previous release.</p><h3 id="approval-status" tabindex="-1">Approval status <a class="header-anchor" href="#approval-status" aria-label="Permalink to &quot;Approval status&quot;">​</a></h3><p>If any stage is awaiting approval, this section lists each environment, the approvals received (with who approved and when), and outstanding approvals.</p><h3 id="activity-log" tabindex="-1">Activity log <a class="header-anchor" href="#activity-log" aria-label="Permalink to &quot;Activity log&quot;">​</a></h3><p>A terminal-style window in the bottom of the page. Reverse-chronological list of events:</p><ul><li>Timestamp.</li><li>Action type badge (failure red, warning orange, success green, info blue).</li><li>Message — instance/user IDs are auto-replaced with human-readable names.</li><li>Actor avatar (User or Agent).</li></ul><p>The activity log is the source of truth for what happened to the release.</p><h2 id="auto-refresh" tabindex="-1">Auto-refresh <a class="header-anchor" href="#auto-refresh" aria-label="Permalink to &quot;Auto-refresh&quot;">​</a></h2><p>While a release is <code>in_progress</code> (or a stage is deploying / awaiting approval / awaiting trigger), the page auto-refreshes every 5 seconds. There is no manual refresh button — reload the page if you need to.</p>',61)])])}const v=r(l,[["render",d]]);export{b as __pageData,v as default};
